#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define MIN(a, b) ((a) < (b) ? (a) : (b))

__kernel void dynproc_kernel(const int iteration,
                             __global const int *gpuWall,
                             __global const int *gpuSrc,
                             __global int *gpuResults,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int border,
                             const int HALO,
                             __local int *prev,
                             __local int *result,
                             __global int *outputBuffer)
{
    const int tx = (int)get_local_id(0);
    const int bx = (int)get_group_id(0);
    const int localSize = (int)get_local_size(0);

    const int small_block_cols = localSize - iteration * HALO * 2;
    if (small_block_cols <= 0) {
        return;
    }

    const int blkX = small_block_cols * bx - border;
    const int blkXmax = blkX + localSize - 1;
    const int xidx = blkX + tx;

    const int validXmin = (blkX < 0) ? (-blkX) : 0;
    const int validXmax = (blkXmax > (cols - 1))
                              ? (localSize - 1 - (blkXmax - (cols - 1)))
                              : (localSize - 1);

    const int isValid = IN_RANGE(tx, validXmin, validXmax) && IN_RANGE(xidx, 0, cols - 1);

    if (isValid) {
        prev[tx] = gpuSrc[xidx];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;

    for (int i = 0; i < iteration; i++) {
        computed = 0;

        if (IN_RANGE(tx, i + 1, localSize - i - 2) && isValid) {
            const int up = prev[tx];
            const int left = (tx == validXmin) ? up : prev[tx - 1];
            const int right = (tx == validXmax) ? up : prev[tx + 1];
            const int shortest = MIN(MIN(left, up), right);
            result[tx] = shortest + gpuWall[(startStep + i) * cols + xidx];
            computed = 1;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1) {
            break;
        }

        if (computed) {
            prev[tx] = result[tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result[tx];
    }

    if (get_global_id(0) == 0) {
        outputBuffer[0] = 0;
    }

    (void)rows;
}
